import type { UmbEntryPointOnInit } from '@umbraco-cms/backoffice/extension-api';
import { register, setup, start } from './shadow-injector';

import globalCSS from './mobile.scss?inline';
import umbBackofficeHeaderCSS from './injects/css/umb-backoffice-header.scss?inline';
import umbSplitPanelCSS from './injects/css/umb-split-panel.scss?inline';
import umbBodyLayoutCSS from './injects/css/umb-body-layout.scss?inline';
import umbWorkspaceFooterCSS from './injects/css/umb-workspace-footer.scss?inline';
import umbSectionSidebarMenuWithEntityActionsCSS from './injects/css/umb-section-sidebar-menu-with-entity-actions.scss?inline';

import umbSectionSidebarJS from './injects/js/umb-section-sidebar';
import uuiPopoverContainerJS from './injects/js/uui-popover-container';

export const onInit: UmbEntryPointOnInit = (_host, _extensionRegistry) => {
  const style = document.createElement('style');
  style.dataset['kvMobile'] = '';
  style.textContent = globalCSS;
  document.head.appendChild(style);

  register('umb-backoffice-header', umbBackofficeHeaderCSS);
  register('umb-split-panel', umbSplitPanelCSS);
  register('umb-body-layout', umbBodyLayoutCSS);
  register('umb-workspace-footer', umbWorkspaceFooterCSS);
  //register('umb-section-sidebar', umbSectionSidebarCSS);
  register('umb-section-sidebar-menu-with-entity-actions', umbSectionSidebarMenuWithEntityActionsCSS);

  setup('umb-section-sidebar', umbSectionSidebarJS);
  setup('uui-popover-container', uuiPopoverContainerJS);

  start();
};
