import { isMobile, onBreakpointChange } from './mobile-breakpoint';

export default function (host: HTMLElement, _root: ShadowRoot): void {

  function find() {
    setTimeout(() => {
      const elements = host.querySelectorAll('#hidden-tabs-container') as NodeListOf<HTMLElement>;
      if (!elements) { find(); return; }
      if (elements.length > 0) { wire(elements); return; }
    }, 10);
  }

  function wire(elements: NodeListOf<HTMLElement>) {
    elements.forEach(element => {
      if (element.children.length === 0) {
        setTimeout(() => {
          Array.from(element.children).forEach(el => {
            el.classList.add('kv-popover-item');
            el.addEventListener('click', () => {
              if (!isMobile()) return;
              const label = el.getAttribute('label');
              const map: Record<string, string> = {
                'Settings':    '/umbraco/section/settings',
                'Content':     '/umbraco/section/content',
                'Media':       '/umbraco/section/media',
                'Members':     '/umbraco/section/members',
                'Forms':       '/umbraco/section/forms',
                'Engage':      '/umbraco/section/engage',
                'Packages':    '/umbraco/section/packages',
                'Users':       '/umbraco/section/users',
                'Translation': '/umbraco/section/translation',
              };
              if (label && map[label]) window.location.href = map[label];
            });
          });
        }, 1000);
      }
    });
  }

  if (isMobile()) find();
  onBreakpointChange(mobile => { if (mobile) find(); });
}
