import { isMobile, onBreakpointChange } from './mobile-breakpoint';

export default function (host: HTMLElement, root: ShadowRoot): void {

  function addExpander() {
    setTimeout(() => {
      const nav = root.querySelector('uui-scroll-container');

      if (!nav) {
        addExpander();
        return;
      }

      nav.addEventListener('click', (e) => {
        if (!isMobile()) return;
        if (e.clientY > 100) return;
        if (host.classList.contains('expanded')) {
          host.classList.remove('expanded');
          host.style.minHeight = '';
          host.style.removeProperty('--kv-sidebar-menu-height');
          host.style.removeProperty('--kv-sidebar-menu-overflow');
        } else {
          host.classList.add('expanded');
          host.style.minHeight = '100%';
          host.style.setProperty('--kv-sidebar-menu-height', '100%');
          host.style.setProperty('--kv-sidebar-menu-overflow', 'visible');
        }
      });
    }, 10);
  }

  addExpander();

  function collapse() {
    if (host.classList.contains('expanded')) {
      host.classList.remove('expanded');
      host.style.minHeight = '';
      host.style.removeProperty('--kv-sidebar-menu-height');
      host.style.removeProperty('--kv-sidebar-menu-overflow');
    }
  }

  window.addEventListener('popstate', () => { if (isMobile()) collapse(); });

  const originalPushState = history.pushState.bind(history);
  history.pushState = function (...args: Parameters<typeof history.pushState>) {
    originalPushState(...args);
    if (isMobile()) collapse();
  };

  // Collapse when resizing back to desktop
  onBreakpointChange(mobile => { if (!mobile) collapse(); });
}
