type SetupFn = (host: HTMLElement, root: ShadowRoot) => void;

interface TagConfig {
  css?: string;
  setup?: SetupFn;
}

// parentTag → (childTag → css) — inject into childTag only when inside parentTag
const scopedMap = new Map<string, Map<string, string>>();

const configMap = new Map<string, TagConfig>();
const observedRoots = new WeakSet<ShadowRoot>();

function hasAncestor(el: Element, ancestorTag: string): boolean {
  let current: Element | null = el;
  while (current) {
    if (current.localName === ancestorTag) return true;
    const root = current.getRootNode();
    current = root instanceof ShadowRoot ? root.host : null;
  }
  return false;
}

function injectCSS(el: Element, css: string): void {
  const { shadowRoot } = el;
  if (!shadowRoot || shadowRoot.querySelector('style[data-kv-mobile]')) return;
  const style = document.createElement('style');
  style.dataset['kvMobile'] = '';
  style.textContent = css;
  shadowRoot.appendChild(style);
}

function applyConfig(el: Element, config: TagConfig): void {
  if (!el.shadowRoot) {
    requestAnimationFrame(() => applyConfig(el, config));
    return;
  }

  if (config.css) injectCSS(el, config.css);
  if (config.setup) config.setup(el as HTMLElement, el.shadowRoot);

  observeRoot(el.shadowRoot);
}

function applyScopedConfig(el: Element): void {
  for (const [parentTag, children] of scopedMap) {
    const css = children.get(el.localName);
    if (css && hasAncestor(el, parentTag)) {
      if (el.shadowRoot) injectCSS(el, css);
      else waitForShadowRootThen(el, child => injectCSS(child, css));
    }
  }
}

function deepQueryAll(root: Element | ShadowRoot, selector: string): Element[] {
  const results: Element[] = [];
  root.querySelectorAll(selector).forEach(el => results.push(el));
  root.querySelectorAll('*').forEach(el => {
    if (el.shadowRoot) deepQueryAll(el.shadowRoot, selector).forEach(r => results.push(r));
  });
  return results;
}

function waitForShadowRoot(el: Element): void {
  if (!el.isConnected) return;
  if (el.shadowRoot) { observeRoot(el.shadowRoot); return; }
  requestAnimationFrame(() => waitForShadowRoot(el));
}

function waitForShadowRootThen(el: Element, fn: (el: Element) => void): void {
  if (!el.isConnected) return;
  if (el.shadowRoot) { fn(el); return; }
  requestAnimationFrame(() => waitForShadowRootThen(el, fn));
}

function processElement(el: Element): void {
  const config = configMap.get(el.localName);
  if (config) {
    applyConfig(el, config);
  } else if (el.shadowRoot) {
    observeRoot(el.shadowRoot);
  } else if (el.localName.includes('-')) {
    waitForShadowRoot(el);
  }

  applyScopedConfig(el);
}

function observeRoot(root: ShadowRoot | Document): void {
  if (root instanceof ShadowRoot) {
    if (observedRoots.has(root)) return;
    observedRoots.add(root);
  }

  new MutationObserver(mutations => {
    for (const { addedNodes } of mutations) {
      for (const node of addedNodes) {
        if (!(node instanceof Element)) continue;
        processElement(node);
        node.querySelectorAll('*').forEach(el => processElement(el));
      }
    }
  }).observe(root instanceof Document ? document.body : root, { childList: true, subtree: true });

  const rootEl = root instanceof Document ? document.documentElement : root;
  rootEl.querySelectorAll('*').forEach(processElement);
}

function getOrCreate(tag: string): TagConfig {
  if (!configMap.has(tag)) configMap.set(tag, {});
  return configMap.get(tag)!;
}

export function register(tag: string, css: string): void {
  getOrCreate(tag).css = css;
}

export function setup(tag: string, fn: SetupFn): void {
  getOrCreate(tag).setup = fn;
}

export function registerWithin(parentTag: string, childTag: string, css: string): void {
  if (!scopedMap.has(parentTag)) scopedMap.set(parentTag, new Map());
  scopedMap.get(parentTag)!.set(childTag, css);
}

export function start(): void {
  observeRoot(document);
}
